SELECT COUNT(*) AS TOTAL_PARTICIPACOES FROM LATTES_ORIENTACAO LO JOIN SERVIDOR S ON S.PK_SIAPE = LO.FK_SIAPE WHERE S.GENERO = 'MASCULINO' AND S.SIGLA_CAMPUS = 'FOR' AND LOWER(COALESCE(S.AREA_INGRESSO, '')) LIKE '%biologia geral%' AND LOWER(LO.TIPO) LIKE LOWER('iniciacao cientifica%') AND LO.ANO >= (CAST(strftime('%Y', 'now') AS INTEGER) - 4);